import React, { useState, useEffect } from 'react';

const ResultsMarquee = () => {
    // Sample data - Replace with your actual last year's results
    const [results, setResults] = useState([]);
    const [isPaused, setIsPaused] = useState(false);

    // Last year's winners data - Update this with your actual data
    const lastYearData = [
        { position: 1, grade: 10, team: "The Innovators", project: "Solar Water Purifier", students: "Aarav, Priya" },
        { position: 2, grade: 10, team: "Science Squad", project: "Bio-Diesel from Waste", students: "Rohan, Sneha" },
        { position: 3, grade: 10, team: "Green Minds", project: "Vertical Farming", students: "Vikram, Anjali" },
        { position: 1, grade: 9, team: "Tech Wizards", project: "Smart Irrigation System", students: "Kiran, Meera" },
        { position: 2, grade: 9, team: "Eco Warriors", project: "Plastic Recycling", students: "Amit, Neha" },
        { position: 3, grade: 9, team: "Future Scientists", project: "Wind Energy Model", students: "Suresh, Deepa" },
        { position: 1, grade: 8, team: "Robo Geeks", project: "Line Following Robot", students: "Raj, Simran" },
        { position: 2, grade: 8, team: "Creative Minds", project: "Water Quality Tester", students: "Mohit, Kavya" },
        { position: 3, grade: 8, team: "Young Engineers", project: "Smart Street Light", students: "Arjun, Pooja" },
        { position: 1, grade: 7, team: "Bio Innovators", project: "Composting Machine", students: "Sahil, Riya" },
        { position: 2, grade: 7, team: "Green Thumbs", project: "Hydroponics System", students: "Manish, Tina" },
        { position: 3, grade: 7, team: "Eco Stars", project: "Rainwater Harvesting", students: "Kunal, Sara" },
        { position: 1, grade: 6, team: "Little Einsteins", project: "Volcano Experiment", students: "Aryan, Ishita" },
        { position: 2, grade: 6, team: "Science Stars", project: "Magnetic Levitation", students: "Pranav, Nisha" },
        { position: 3, grade: 6, team: "Young Explorers", project: "Solar Oven", students: "Rahul, Ananya" },
        { position: 1, grade: 5, team: "Mini Scientists", project: "Plant Growth Study", students: "Neel, Sara" },
        { position: 2, grade: 5, team: "Curious Minds", project: "Simple Circuit", students: "Rishi, Aanya" },
        { position: 3, grade: 5, team: "Tiny Innovators", project: "Water Filter", students: "Arnav, Kavya" },
        { position: 1, grade: 4, team: "Smart Kids", project: "Weather Station", students: "Ishaan, Anvi" },
        { position: 2, grade: 4, team: "Wonder Kids", project: "Seed Germination", students: "Ayaan, Diya" },
        { position: 3, grade: 4, team: "Bright Minds", project: "Shadow Study", students: "Veer, Myra" },
        { position: 1, grade: 3, team: "Little Geniuses", project: "Sink or Float", students: "Shaurya, Tara" },
        { position: 2, grade: 3, team: "Tiny Tots", project: "Color Mixing", students: "Aarush, Isha" },
        { position: 3, grade: 3, team: "Mini Explorers", project: "Plant Life Cycle", students: "Reyansh, Zara" },
    ];

    useEffect(() => {
        // Double the data for seamless scrolling
        setResults([...lastYearData, ...lastYearData, ...lastYearData]);
    }, []);

    // Get medal emoji
    const getMedal = (position) => {
        const medals = ['🥇', '🥈', '🥉'];
        return medals[position - 1] || '🏅';
    };

    // Get medal color
    const getMedalColor = (position) => {
        const colors = ['text-yellow-500', 'text-gray-400', 'text-amber-600'];
        return colors[position - 1] || 'text-blue-500';
    };

    return (
        <div 
            className="bg-gradient-to-r from-blue-950 via-blue-900 to-blue-800 border-y-4 border-yellow-400 overflow-hidden relative shadow-lg"
            onMouseEnter={() => setIsPaused(true)}
            onMouseLeave={() => setIsPaused(false)}
        >
            {/* Header */}
            <div className="absolute top-0 left-0 right-0 z-10 bg-blue-900/90 px-4 py-2 text-center border-b border-yellow-400/30">
                <div className="flex items-center justify-center gap-4">
                    <span className="text-2xl">🏆</span>
                    <span className="text-yellow-400 font-bold text-sm md:text-lg uppercase tracking-wider">
                        Last Year's Science Fair Winners 2025-26
                    </span>
                    <span className="text-2xl">🏆</span>
                </div>
            </div>

            {/* Marquee Container */}
            <div className="pt-12 pb-4 overflow-hidden h-[350px] relative">
                <div 
                    className={`absolute inset-0 flex flex-col ${!isPaused ? 'animate-marquee-vertical' : ''}`}
                    style={{
                        animationDuration: '45s',
                        animationTimingFunction: 'linear',
                        animationIterationCount: 'infinite',
                    }}
                >
                    {results.map((result, index) => (
                        <div 
                            key={index}
                            className={`flex items-center justify-between px-4 md:px-8 py-2 border-b border-blue-700/30 hover:bg-blue-800/30 transition-colors flex-shrink-0 ${
                                result.position === 1 ? 'bg-yellow-500/10' : ''
                            }`}
                        >
                            <div className="flex items-center gap-3 md:gap-6 flex-1">
                                <span className={`text-xl md:text-2xl ${getMedalColor(result.position)}`}>
                                    {getMedal(result.position)}
                                </span>
                                <div className="flex-1">
                                    <span className="text-white font-semibold text-sm md:text-base">
                                        {result.team}
                                    </span>
                                    <span className="text-blue-300 text-xs md:text-sm ml-2 hidden sm:inline">
                                        - {result.project}
                                    </span>
                                </div>
                            </div>
                            <div className="flex items-center gap-2 md:gap-4 flex-shrink-0">
                                <span className="text-yellow-400 font-bold text-sm md:text-base">
                                    Grade {result.grade}
                                </span>
                                <span className="text-blue-300 text-xs hidden md:inline">
                                    {result.students}
                                </span>
                                <span className="bg-yellow-500/20 text-yellow-300 px-2 py-0.5 rounded text-xs font-bold">
                                    {result.position === 1 ? '🏆 Winner' : result.position === 2 ? '🥈 Runner-up' : '🥉 Second Runner-up'}
                                </span>
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            {/* Bottom Gradient */}
            <div className="absolute bottom-0 left-0 right-0 h-8 bg-gradient-to-t from-blue-950 to-transparent"></div>

            {/* CSS Animation */}
            <style jsx>{`
                @keyframes marquee-vertical {
                    0% { transform: translateY(0); }
                    100% { transform: translateY(-33.33%); }
                }
                .animate-marquee-vertical {
                    animation: marquee-vertical 45s linear infinite;
                }
                .animate-marquee-vertical:hover {
                    animation-play-state: paused;
                }
            `}</style>
        </div>
    );
};

export default ResultsMarquee;
